import { Metadata } from "next";
import contentData from "@/data/content.json";
import Navbar from "@/components/layout/Navbar";
import OrderDrawer from "@/components/layout/OrderDrawer";
import Footer from "@/components/layout/Footer";
import HeroSection from "@/components/sections/HeroSection";
import TrustBanner from "@/components/sections/TrustBanner";
import HighlightsSection from "@/components/sections/HighlightsSection";
import ProductsSection from "@/components/sections/ProductsSection";
import TestimonialsSection from "@/components/sections/TestimonialsSection";
import CtaSection from "@/components/sections/CtaSection";
import FindUsSection from "@/components/sections/FindUsSection";

export const metadata: Metadata = {
  title: "SakharSansar | Pure & Natural from Sankhuwasabha",
  description: "Experience the authentic taste of 100% natural, chemical-free jaggery direct from farmers in Sankhuwasabha, Nepal. Order pure Himalayan gur.",
  keywords: ["Jaggery", "Natural Jaggery", "Sankhuwasabha", "Nepal", "SakharSansar", "Organic Gur", "Chemical Free", "Sweetener"],
  alternates: {
    canonical: "https://sakharsansar.com",
  },
  openGraph: {
    title: "SakharSansar | Pure & Natural from Sankhuwasabha",
    description: "Experience the authentic taste of 100% natural, chemical-free jaggery direct from farmers in Sankhuwasabha, Nepal. Order pure Himalayan gur.",
    url: "https://sakharsansar.com",
    siteName: "SakharSansar",
    images: [
      {
        url: "/hero.jpg",
        width: 1200,
        height: 630,
        alt: "Pure SakharSansar from Sankhuwasabha",
      },
    ],
    locale: "en_US",
    type: "website",
  },
  twitter: {
    card: "summary_large_image",
    title: "SakharSansar | Pure & Natural",
    description: "100% natural, chemical-free jaggery direct from farmers in Sankhuwasabha, Nepal.",
    images: ["/hero.jpg"],
  },
};

export default function Home() {
  const jsonLd = {
    "@context": "https://schema.org",
    "@type": "LocalBusiness",
    "name": "SakharSansar",
    "image": "https://sakharsansar.com/hero.jpg",
    "description": "Pure, Chemical-Free Jaggery sourced directly from farmers in Sankhuwasabha, Nepal.",
    "address": {
      "@type": "PostalAddress",
      "addressLocality": "Sankhuwasabha",
      "addressRegion": "Koshi Province",
      "addressCountry": "NP"
    },
    "priceRange": "$$",
    "url": "https://sakharsansar.com"
  };

  const productsJsonLd = contentData.products.map(product => ({
    "@context": "https://schema.org",
    "@type": "Product",
    "name": product.name,
    "description": product.description,
    "image": `https://sakharsansar.com${product.image}`,
    "brand": {
      "@type": "Brand",
      "name": "SakharSansar"
    },
    "offers": {
      "@type": "Offer",
      "price": product.price.replace(/[^0-9]/g, ''),
      "priceCurrency": "NPR",
      "availability": "https://schema.org/InStock",
      "seller": {
        "@type": "Organization",
        "name": "SakharSansar"
      }
    },
    "weight": {
      "@type": "QuantitativeValue",
      "value": product.weight.replace(/[^0-9.]/g, ''),
      "unitCode": "KGM"
    }
  }));

  return (
    <>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
      {productsJsonLd.map((productLd, i) => (
        <script
          key={i}
          type="application/ld+json"
          dangerouslySetInnerHTML={{ __html: JSON.stringify(productLd) }}
        />
      ))}

      <header>
        <Navbar />
      </header>
      <OrderDrawer />
      <main className="overflow-x-hidden">
        <HeroSection />
        <TrustBanner />
        {/* <HighlightsSection /> */}
        <ProductsSection />
        <TestimonialsSection />
        <FindUsSection />
        <CtaSection />
      </main>
      <Footer />
    </>
  );
}

"use client";
import { useState, useEffect, useRef, useCallback } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Menu, X, ShoppingBag } from 'lucide-react';
import { openOrderDrawer } from './OrderDrawer';

export default function Navbar() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const navRef = useRef<HTMLElement>(null);
  const pathname = usePathname();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close mobile menu on route change
  useEffect(() => {
    setMobileOpen(false);
  }, [pathname]);

  useEffect(() => {
    if (mobileOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [mobileOpen]);

  const closeMobile = useCallback(() => setMobileOpen(false), []);

  return (
    <>
      <nav
        ref={navRef}
      aria-label="Main navigation"
      className={`fixed top-0 w-full z-50 transition-all duration-500 ${scrolled
        ? 'bg-white/95 backdrop-blur-md py-2 shadow-sm'
        : 'bg-white py-3'
        } px-4 sm:px-10 lg:px-16`}
    >
      <div className="flex items-center justify-between">
        {/* Left: Word Logo */}
        <Link href="/" className="shrink-0">
          <Image
            src="/word-logo.svg"
            alt="SakharSansar"
            width={240}
            height={60}
            className="h-[51px] sm:h-[67px] w-auto"
            priority
          />
        </Link>

        {/* Center: Company Logo */}
        <div className="absolute left-1/2 -translate-x-1/2 overflow-visible">
          <Link href="/">
            <Image
              src="/company-logo.svg"
              alt="SakharSansar Logo"
              width={80}
              height={80}
              className={`transition-all duration-500 ${scrolled ? 'h-14 w-14 sm:h-16 sm:w-16' : 'h-16 w-16 sm:h-20 sm:w-20'}`}
              priority
            />
          </Link>
        </div>

        {/* Right: Desktop nav */}
        <div className="hidden md:flex gap-8 lg:gap-10 text-[15px] font-medium items-center text-[#2C1500]">
          <Link href="/our-story" className="hover:text-[#C17A2A] transition duration-300">Our Story</Link>
          <Link href="/shop" className="hover:text-[#C17A2A] transition duration-300">Shop</Link>
          <Link href="/blog" className="hover:text-[#C17A2A] transition duration-300">Blog</Link>
          <button
            onClick={() => openOrderDrawer()}
            className="ml-2 inline-flex items-center gap-2 px-7 py-3 bg-[#C17A2A] text-white rounded-full text-[15px] font-semibold hover:bg-[#A8671F] transition duration-300"
          >
            <ShoppingBag className="w-4 h-4" strokeWidth={2} />
            Order Now
          </button>
        </div>

        {/* Mobile hamburger */}
        <button
          className="md:hidden text-[#2C1500] p-2 -mr-2 touch-manipulation relative z-50 flex-shrink-0"
          onClick={() => setMobileOpen(!mobileOpen)}
          aria-label={mobileOpen ? "Close menu" : "Open menu"}
          aria-expanded={mobileOpen}
        >
          {mobileOpen ? <X className="w-6 h-6 sm:w-7 sm:h-7" strokeWidth={1.5} /> : <Menu className="w-6 h-6 sm:w-7 sm:h-7" strokeWidth={1.5} />}
        </button>
      </div>
    </nav>

      {/* Mobile menu overlay */}
      <div
        className={`fixed inset-x-0 top-0 bottom-0 bg-white z-40 flex flex-col items-center justify-start gap-6 sm:gap-8 md:hidden transition-all duration-300 overflow-y-auto pb-10 ${mobileOpen
          ? 'opacity-100 translate-y-0 pointer-events-auto'
          : 'opacity-0 -translate-y-4 pointer-events-none'
          }`}
        style={{ paddingTop: `calc(${navRef.current?.offsetHeight ?? 72}px + 2rem)` }}
      >
        <Link href="/our-story" onClick={closeMobile} className="font-poppins text-xl sm:text-2xl font-semibold text-[#2C1500] hover:text-[#C17A2A] active:text-[#C17A2A] transition">
          Our Story
        </Link>
        <Link href="/shop" onClick={closeMobile} className="font-poppins text-xl sm:text-2xl font-semibold text-[#2C1500] hover:text-[#C17A2A] active:text-[#C17A2A] transition">
          Shop
        </Link>
        <Link href="/blog" onClick={closeMobile} className="font-poppins text-xl sm:text-2xl font-semibold text-[#2C1500] hover:text-[#C17A2A] active:text-[#C17A2A] transition">
          Blog
        </Link>
        <button
          onClick={() => { closeMobile(); openOrderDrawer(); }}
          className="inline-flex items-center gap-3 mt-4 px-8 py-3.5 bg-[#C17A2A] text-white rounded-full text-base sm:text-lg font-semibold hover:bg-[#A8671F] active:bg-[#A8671F] transition duration-300"
        >
          <ShoppingBag className="w-5 h-5" strokeWidth={2} />
          Order Now
        </button>
      </div>
    </>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { X, CheckCircle } from 'lucide-react';
import data from "@/data/content.json";
import JaggeryLoader from "../ui/JaggeryLoader";

export const openOrderDrawer = (productName?: string) => {
  if (typeof window !== 'undefined') {
    window.dispatchEvent(new CustomEvent('open-order-drawer', { detail: { productName } }));
  }
};

export default function OrderDrawer() {
  const [isOpen, setIsOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState("");
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    address: "",
    quantity: "1",
  });

  useEffect(() => {
    const handleOpen = (e: Event) => {
      const customEvent = e as CustomEvent;
      if (customEvent.detail?.productName) {
        setSelectedProduct(customEvent.detail.productName);
      }
      setIsOpen(true);
      setIsSubmitted(false);
      document.body.style.overflow = 'hidden';
    };

    window.addEventListener('open-order-drawer', handleOpen);
    return () => window.removeEventListener('open-order-drawer', handleOpen);
  }, []);

  const closeDrawer = () => {
    setIsOpen(false);
    document.body.style.overflow = 'auto';
  };

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    // Simulate API call
    setTimeout(() => {
      setIsLoading(false);
      setIsSubmitted(true);
    }, 1500);
  };

  return (
    <>
      <div 
        className="fixed inset-0 bg-black/40 z-[90] transition-opacity duration-300"
        onClick={closeDrawer}
      />
      
      <div
        role="dialog"
        aria-modal="true"
        aria-label={isSubmitted ? "Order confirmed" : "Place your order"}
        className={`fixed right-0 top-0 h-full w-full sm:w-[500px] bg-[#F4F1ED] z-[100] transform transition-transform duration-500 ease-[cubic-bezier(0.25,1,0.5,1)] flex flex-col`}
      >
        <div className="flex justify-between items-center p-6 sm:p-10 border-b border-black/10 bg-white">
          <h2 className="font-poppins text-xl font-medium tracking-[0.1em] uppercase text-black">
            {isSubmitted ? "Order Confirmed" : "Place Order"}
          </h2>
          <button onClick={closeDrawer} className="text-black/50 hover:text-black transition-colors">
            <X className="w-6 h-6" strokeWidth={1.5} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 sm:p-10 flex flex-col">
          {isLoading ? (
            <div className="flex-1 flex items-center justify-center">
              <JaggeryLoader />
            </div>
          ) : isSubmitted ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-6 animate-in fade-in duration-500">
              <CheckCircle className="w-16 h-16 text-black" strokeWidth={1} />
              <h3 className="font-poppins text-2xl font-medium tracking-[0.1em] uppercase text-black">Thank You</h3>
              <p className="text-black/60 text-sm tracking-widest leading-loose">
                Your order for {formData.quantity}x {selectedProduct || "Jaggery"} has been received. <br/><br/>We will contact you at {formData.phone} shortly to arrange delivery.
              </p>
              <button 
                onClick={closeDrawer}
                className="mt-8 px-8 py-4 bg-black text-white text-[10px] font-semibold tracking-[0.2em] uppercase hover:bg-black/80 transition-colors"
              >
                Close Window
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="flex flex-col gap-8">
              <div className="flex flex-col gap-2">
                <label className="text-[10px] font-semibold tracking-[0.2em] text-black/50 uppercase">Select Product</label>
                <select 
                  className="w-full bg-white border border-black/10 px-4 py-3 text-sm focus:border-black outline-none font-poppins text-black transition-colors"
                  value={selectedProduct}
                  onChange={(e) => setSelectedProduct(e.target.value)}
                  required
                >
                  <option value="" disabled>Choose a product</option>
                  {data.products.map((p: any) => (
                    <option key={p.name} value={p.name}>{p.name} - {p.price}</option>
                  ))}
                  <option value="Custom Order">Custom / Bulk Order</option>
                </select>
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-[10px] font-semibold tracking-[0.2em] text-black/50 uppercase">Quantity</label>
                <div className="flex border border-black/10 bg-white">
                  {['1', '2', '3', '5', '10'].map(num => (
                    <button
                      key={num}
                      type="button"
                      onClick={() => setFormData({...formData, quantity: num})}
                      className={`flex-1 py-3 text-sm font-poppins transition-colors border-r last:border-r-0 border-black/10 ${formData.quantity === num ? 'bg-black text-white' : 'text-black hover:bg-black/5'}`}
                    >
                      {num}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-[10px] font-semibold tracking-[0.2em] text-black/50 uppercase">Full Name</label>
                <input 
                  type="text" 
                  required
                  className="w-full bg-white border border-black/10 px-4 py-3 text-sm focus:border-black outline-none text-black transition-colors"
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  placeholder="Your Name"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-[10px] font-semibold tracking-[0.2em] text-black/50 uppercase">Phone Number</label>
                <input 
                  type="tel" 
                  required
                  className="w-full bg-white border border-black/10 px-4 py-3 text-sm focus:border-black outline-none text-black transition-colors"
                  value={formData.phone}
                  onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  placeholder="+977"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-[10px] font-semibold tracking-[0.2em] text-black/50 uppercase">Delivery Address</label>
                <textarea 
                  required
                  rows={3}
                  className="w-full bg-white border border-black/10 px-4 py-3 text-sm focus:border-black outline-none text-black transition-colors resize-none"
                  value={formData.address}
                  onChange={(e) => setFormData({...formData, address: e.target.value})}
                  placeholder="City, Street, House No."
                />
              </div>

              <button 
                type="submit" 
                className="mt-4 w-full py-4 bg-black text-white text-[10px] font-semibold tracking-[0.2em] uppercase hover:bg-black/80 transition-colors"
              >
                Complete Order
              </button>
            </form>
          )}
        </div>
      </div>
    </>
  );
}

import React from 'react';
import data from "@/data/content.json";
import { ZoomIn, FadeUp } from "@/components/Animations";
import { Check } from "lucide-react";

export default function TrustBanner() {
  return (
    <section aria-label="Trust Badges" className="py-10 sm:py-14 bg-[#2C1500]">
      <div className="max-w-[1440px] mx-auto px-6 sm:px-10">
        <div className="grid grid-cols-2 lg:flex lg:flex-wrap lg:justify-center gap-4 gap-y-6 sm:gap-8 md:gap-20">
          {data.trustBanner.badges.map((badge, i) => (
            <FadeUp key={i} delay={i * 0.08}>
              <div className="flex items-center gap-2.5 sm:gap-3 text-white">
                <div className="w-6 h-6 sm:w-8 sm:h-8 rounded-full bg-[#C17A2A] flex items-center justify-center shrink-0">
                  <Check className="w-3.5 h-3.5 sm:w-4 sm:h-4 text-white" strokeWidth={2.5} />
                </div>
                <span className="text-xs sm:text-base font-medium text-white/90 leading-tight">{badge}</span>
              </div>
            </FadeUp>
          ))}
        </div>
      </div>
    </section>
  );
}
